export function sliceClientPagedRows<T>(
  allItems: T[],
  page: number,
  pageSize: number,
  footerPaginationEnabled: boolean,
): { rows: T[]; totalCount: number; effectivePage: number; effectivePageSize: number } {
  const totalCount = allItems.length;
  if (!footerPaginationEnabled || pageSize <= 0) {
    return {
      rows: allItems,
      totalCount,
      effectivePage: 1,
      effectivePageSize: Math.max(totalCount, 1),
    };
  }

  const effectivePageSize = pageSize;
  const maxPage = totalCount === 0 ? 1 : Math.max(1, Math.ceil(totalCount / effectivePageSize));
  const effectivePage = Math.min(Math.max(1, page), maxPage);
  const start = (effectivePage - 1) * effectivePageSize;
  return {
    rows: allItems.slice(start, start + effectivePageSize),
    totalCount,
    effectivePage,
    effectivePageSize,
  };
}

export function clientReportRowNo(index: number, page: number, pageSize: number): number {
  if (pageSize <= 0) return index + 1;
  return (page - 1) * pageSize + index + 1;
}
