import {
  resolveReportCharts,
  type ErpReportChartCatalogItem,
  type ErpReportDisplayConfig,
} from '@linm-soft/common-components';
import { isReportChartsEnabled } from './erpReportChartPrefs';

export type ReportChartQueryParams = {
  includeChartData?: boolean;
  chartIds?: string;
};

/** Map report display config → GET ledger query (report-page-layout §6.2). */
export function buildReportChartQueryParams(
  displayConfig: ErpReportDisplayConfig,
  catalog: readonly ErpReportChartCatalogItem[],
): ReportChartQueryParams {
  if (!isReportChartsEnabled(displayConfig.chart)) {
    return { includeChartData: false };
  }

  if (catalog.length === 0) {
    const ids = displayConfig.chart.enabledChartIds;
    if (ids.length > 0) {
      return { chartIds: ids.join(',') };
    }
    return {};
  }

  const visible = resolveReportCharts(catalog, displayConfig.chart);
  if (visible.length === 0) {
    return { includeChartData: false };
  }

  if (
    displayConfig.chart.enabledChartIds.length > 0
    && visible.length < catalog.length
  ) {
    return { chartIds: visible.map(c => c.chartId).join(',') };
  }

  return {};
}
