import type { LedgerEntryDto } from '../../services/kt/models';
import { formatDateLocal } from '../../utils/formatters';

export type LedgerBalancePoint = {
  label: string;
  balance: number;
  debit: number;
  credit: number;
};

export type LedgerDailyPoint = {
  label: string;
  debit: number;
  credit: number;
};

export type LedgerChartSummary = {
  totalDebit: number;
  totalCredit: number;
  closingBalance: number;
  entryCount: number;
};

export type LedgerDonutPoint = {
  name: string;
  value: number;
  fill: string;
};

export type LedgerChartData = {
  balanceSeries: LedgerBalancePoint[];
  dailySeries: LedgerDailyPoint[];
  donutSeries: LedgerDonutPoint[];
  summary: LedgerChartSummary;
};

const DONUT_COLORS = { debit: '#1677ff', credit: '#fa8c16' } as const;

export function buildLedgerChartData(items: LedgerEntryDto[]): LedgerChartData {
  const balanceSeries: LedgerBalancePoint[] = items.map(r => ({
    label: formatDateLocal(r.entryDate),
    balance: r.runningBalance,
    debit: r.debitAmount,
    credit: r.creditAmount,
  }));

  const dailyMap = new Map<string, { debit: number; credit: number }>();
  for (const r of items) {
    const day = r.entryDate.slice(0, 10);
    const cur = dailyMap.get(day) ?? { debit: 0, credit: 0 };
    cur.debit += r.debitAmount;
    cur.credit += r.creditAmount;
    dailyMap.set(day, cur);
  }

  const dailySeries: LedgerDailyPoint[] = [...dailyMap.entries()]
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([day, v]) => ({
      label: formatDateLocal(day),
      debit: v.debit,
      credit: v.credit,
    }));

  const totalDebit = items.reduce((s, r) => s + r.debitAmount, 0);
  const totalCredit = items.reduce((s, r) => s + r.creditAmount, 0);
  const closingBalance = items.length > 0 ? items[items.length - 1].runningBalance : 0;

  const donutSeries: LedgerDonutPoint[] = [
    { name: 'PS Nợ', value: totalDebit, fill: DONUT_COLORS.debit },
    { name: 'PS Có', value: totalCredit, fill: DONUT_COLORS.credit },
  ].filter(p => p.value > 0);

  return {
    balanceSeries,
    dailySeries,
    donutSeries,
    summary: {
      totalDebit,
      totalCredit,
      closingBalance,
      entryCount: items.length,
    },
  };
}

export type NormalizedReportChartKind = 'line' | 'bar' | 'donut';

export function normalizeReportChartKind(kind: string): NormalizedReportChartKind | null {
  const k = kind.trim().toLowerCase();
  if (k === 'line') return 'line';
  if (k === 'bar') return 'bar';
  if (k === 'donut') return 'donut';
  return null;
}

/** Compact VND axis ticks (triệu / tỷ). */
export function formatChartVndAxis(value: number): string {
  const n = Number(value);
  if (!Number.isFinite(n)) return '0';
  const abs = Math.abs(n);
  if (abs >= 1_000_000_000) return `${(n / 1_000_000_000).toFixed(1)}B`;
  if (abs >= 1_000_000) return `${(n / 1_000_000).toFixed(0)}M`;
  if (abs >= 1_000) return `${(n / 1_000).toFixed(0)}K`;
  return String(Math.round(n));
}
